import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { localCart } from '../services/api';

const CartPage = ({ onToast }) => {
  const [cart, setCart] = useState([]);
  const navigate = useNavigate();

  useEffect(() => { setCart(localCart.get()); }, []);

  const update = (id, qty) => {
    const c = localCart.get().map(i => i.id === id ? { ...i, quantity: qty } : i).filter(i => i.quantity > 0);
    localCart.set(c); setCart(c);
    window.dispatchEvent(new Event('cartUpdated'));
  };

  const remove = (id) => {
    const c = localCart.get().filter(i => i.id !== id);
    localCart.set(c); setCart(c);
    window.dispatchEvent(new Event('cartUpdated'));
    onToast?.('Item removed', 'info');
  };

  const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);

  if (cart.length === 0) return (
    <div className="text-center py-5">
      <div style={{ fontSize: '5rem' }}>🛒</div>
      <h4 className="fw-bold mt-3">Your cart is empty</h4>
      <p className="text-muted">Add some amazing tech products!</p>
      <Link to="/products" className="btn btn-warning btn-lg fw-bold mt-2">🛍️ Browse Products</Link>
    </div>
  );

  return (
    <div>
      <h4 className="fw-bold mb-4">🛒 Shopping Cart <span className="badge bg-warning text-dark">{cart.length} items</span></h4>
      <div className="row g-4">
        <div className="col-lg-8">
          {cart.map(item => (
            <div key={item.id} className="card border-0 shadow-sm mb-3">
              <div className="card-body">
                <div className="d-flex align-items-center gap-3">
                  <div className="text-center" style={{ fontSize: '2.5rem', minWidth: 56 }}>{item.emoji}</div>
                  <div className="flex-grow-1">
                    <h6 className="fw-bold mb-1">{item.name}</h6>
                    <div className="d-flex gap-2 mb-2">
                      <span className="badge bg-primary" style={{ fontSize: '0.65rem' }}>{item.category}</span>
                      <span className="badge bg-secondary" style={{ fontSize: '0.65rem' }}>{item.brand}</span>
                    </div>
                    <div className="fw-bold text-success">₹{item.price.toLocaleString('en-IN')}</div>
                  </div>
                  <div className="d-flex align-items-center gap-2">
                    <button className="btn btn-outline-secondary btn-sm" onClick={() => update(item.id, item.quantity - 1)}>−</button>
                    <span className="fw-bold px-2">{item.quantity}</span>
                    <button className="btn btn-outline-secondary btn-sm" onClick={() => update(item.id, item.quantity + 1)}>+</button>
                    <button className="btn btn-outline-danger btn-sm ms-2" onClick={() => remove(item.id)}>🗑</button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
        <div className="col-lg-4">
          <div className="card border-0 shadow-sm">
            <div className="card-header bg-dark text-white fw-bold">Order Summary</div>
            <div className="card-body">
              {cart.map(i => (
                <div key={i.id} className="d-flex justify-content-between small mb-1">
                  <span className="text-muted text-truncate me-2">{i.emoji} {i.name} ×{i.quantity}</span>
                  <span className="fw-semibold">₹{(i.price * i.quantity).toLocaleString('en-IN')}</span>
                </div>
              ))}
              <hr />
              <div className="d-flex justify-content-between fw-bold fs-5">
                <span>Total</span>
                <span className="text-success">₹{total.toLocaleString('en-IN')}</span>
              </div>
              <button className="btn btn-warning fw-bold w-100 mt-3" onClick={() => navigate('/checkout')}>
                💳 Proceed to Checkout
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CartPage;
